using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
vector<int> v[200001];
queue<int> q;
int deg[100001];
int dp[100001];
int n, m;

void tp()
{
	for (int i = 1; i <= n; i++)
	{
		if (deg[i] == 0)
		{
			q.push(i);
		}
	}
	memset(dp, 0, sizeof(dp));
	dp[1] = 1;
	while (!q.empty())
	{
		int k = q.front();
		q.pop();
		for (auto x : v[k])
		{
			deg[x]--;
			if (deg[x] == 0)
			{
				dp[x] = max(dp[x], dp[k] + 1);
				q.push(x);
			}
		}
	}
}
signed main(void)
{
	cin >> n >> m;
	int x, y;
	for (int i = 1; i <= m; i++)
	{
		cin >> x >> y;
		v[x].push_back(y);
		deg[y]++;
	}


	tp();
	for (int i = 1; i <= n; i++)
	{
		cout << dp[i] + 1 << endl;
	}

	return false;
}
